// Step 2: Attach the "free" plan to both customers in parallel
console.log('Attaching "free" plan to both customers...');

async function attachPlan(customerId, planId) {
  try {
    const result = await autumn.billing.attach({ customerId, planId });
    console.log(`Plan "${planId}" attached for ${customerId}`);
    return result;
  } catch (err) {
    // Treat "same plan already attached" as success (idempotent)
    const body =
      typeof err.body === "string" ? JSON.parse(err.body) : err.body ?? {};
    if (
      err.statusCode === 400 &&
      body.code === "invalid_request" &&
      body.message?.includes("same as the product being attached")
    ) {
      console.log(
        `Plan "${planId}" already attached for ${customerId} — skipping.`
      );
      return null;
    }
    throw err;
  }
}

const [attach1, attach2] = await Promise.all([
  attachPlan("user_test_001", "free"),
  attachPlan("user_test_002", "free"),
]);

